import request from '@/utils/request'

export const profile = {
  // 获取基本信息
  getBasicInfo: () => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'get'
    })
  },

  // 更新基本信息
  updateBasicInfo: (data) => {
    return request({
      url: '/api/v1/users/profile/basic/',
      method: 'put',
      data
    })
  },

  // 获取详细资料
  getProfile: () => {
    return request({
      url: '/api/v1/users/profile/',
      method: 'get'
    })
  },

  // 更新详细资料
  updateProfile: (data) => {
    return request({
      url: '/api/v1/users/profile/',
      method: 'put',
      data
    })
  },

  // 上传头像
  uploadAvatar: (file) => {
    return new Promise((resolve, reject) => {
      const formData = new FormData()
      formData.append('avatar', file)

      // 获取 token
      const token = localStorage.getItem('access_token')
      if (!token) {
        return reject(new Error('未找到认证信息'))
      }

      const xhr = new XMLHttpRequest()
      xhr.open('POST', `${process.env.VUE_APP_API_URL}/api/v1/users/profile/avatar/upload/`)

      // 设置请求头
      xhr.setRequestHeader('Authorization', `Bearer ${token}`)
      xhr.setRequestHeader('Accept', 'application/json')

      // 添加事件监听器
      xhr.upload.onprogress = (e) => {
        if (e.lengthComputable) {
          const percentComplete = (e.loaded / e.total) * 100
          console.log('Upload progress:', percentComplete + '%')
        }
      }

      xhr.onload = () => {
        console.log('XHR Response:', {
          status: xhr.status,
          statusText: xhr.statusText,
          responseText: xhr.responseText,
          responseHeaders: xhr.getAllResponseHeaders()
        })

        if (xhr.status === 200) {
          try {
            const response = JSON.parse(xhr.responseText)
            resolve(response)
          } catch (error) {
            reject(new Error('解析响应失败'))
          }
        } else {
          try {
            const errorResponse = JSON.parse(xhr.responseText)
            reject(new Error(errorResponse.message || '上传失败'))
          } catch (error) {
            reject(new Error(xhr.statusText || '上传失败'))
          }
        }
      }

      xhr.onerror = () => {
        console.error('XHR Error:', {
          status: xhr.status,
          statusText: xhr.statusText,
          responseText: xhr.responseText
        })
        reject(new Error('网络错误'))
      }

      // 添加调试日志
      console.log('Sending request:', {
        url: `${process.env.VUE_APP_API_URL}/api/v1/users/profile/avatar/upload/`,
        method: 'POST',
        token: token ? 'present' : 'missing',
        fileInfo: {
          name: file.name,
          type: file.type,
          size: file.size
        },
        formDataEntries: Array.from(formData.entries())
      })

      xhr.send(formData)
    })
  }
}
